import xml.etree.ElementTree as ET
import re

# Parse both XML files to extract comprehensive API info
def parse_xml_file(filepath, namespace_filter):
    tree = ET.parse(filepath)
    root = tree.getroot()

    types = {}
    members = {}

    for member in root.findall(".//member[@name]"):
        name = member.get('name')
        if name.startswith('T:'):
            typename = name[2:]  # Remove 'T:' prefix
            if typename.startswith(namespace_filter):
                summary = member.find('summary')
                summary_text = (summary.text or "").strip()[:150] if summary is not None else ""
                types[typename] = {
                    'summary': summary_text,
                    'members': []
                }
        elif name.startswith('M:') or name.startswith('P:'):
            # Extract parent type and member name
            parts = name[2:].rsplit('.', 1)
            if len(parts) == 2 and parts[0].startswith(namespace_filter):
                parent_type = parts[0]
                member_name = parts[1]
                summary = member.find('summary')
                summary_text = (summary.text or "").strip()[:100] if summary is not None else ""

                if parent_type not in members:
                    members[parent_type] = []
                members[parent_type].append({
                    'name': member_name,
                    'summary': summary_text
                })

    return types, members

# Parse Agents.AI
print("=== Microsoft.Agents.AI ===\n")
agents_types, agents_members = parse_xml_file(
    "/home/runner/.nuget/packages/microsoft.agents.ai/1.3.0/lib/net8.0/Microsoft.Agents.AI.xml",
    "Microsoft.Agents.AI"
)

key_agents = [t for t in agents_types.keys() if any(x in t for x in ['Agent', 'Tool', 'Options', 'Session', 'Response', 'InvokeOptions'])]
for typename in sorted(key_agents)[:30]:
    print(f"{typename}")
    if typename in agents_members:
        for member in agents_members[typename][:10]:
            print(f"    - {member['name']}")
    if agents_types[typename]['summary']:
        print(f"    Summary: {agents_types[typename]['summary']}\n")

print("\n=== Microsoft.Extensions.AI ===\n")
ext_types, ext_members = parse_xml_file(
    "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.0/lib/net8.0/Microsoft.Extensions.AI.xml",
    "Microsoft.Extensions.AI"
)

key_ext = [t for t in ext_types.keys() if any(x in t for x in ['AIFunction', 'AITool', 'IChatClient', 'ChatMessage', 'ChatOptions', 'ChatResponse'])]
for typename in sorted(key_ext)[:30]:
    print(f"{typename}")
    if typename in ext_members:
        for member in ext_members[typename][:8]:
            print(f"    - {member['name']}")
    if ext_types[typename]['summary']:
        print(f"    Summary: {ext_types[typename]['summary']}\n")

