key_types = [
    ('T:Microsoft.Extensions.AI.IChatClient', 'IChatClient'),
    ('T:Microsoft.Extensions.AI.AIFunction', 'AIFunction'),
    ('T:Microsoft.Extensions.AI.AITool', 'AITool'),
    ('T:Microsoft.Extensions.AI.ChatMessage', 'ChatMessage'),
    ('T:Microsoft.Extensions.AI.ChatOptions', 'ChatOptions'),
    ('T:Microsoft.Extensions.AI.ChatResponse', 'ChatResponse'),
]

found_types = {}
for member in root.findall(".//member[@name]"):
    name = member.get('name')
    for type_name, short_name in key_types:
        if name == type_name:
            summary = member.find('summary')
            summary_text = (summary.text or "").strip()[:100] if summary else ""
            found_types[short_name] = {
                'full_name': name[2:],
                'summary': summary_text
            }

for short_name in [item[1] for item in key_types]:
    if short_name in found_types:
        info = found_types[short_name]
        print(f"\n✓ {short_name}")
        print(f"  Full name: {info['full_name']}")
        if info['summary']:
            print(f"  Description: {info['summary']}")

print("\n2. ICHATCLIENT METHODS")
print("-" * 80)
print("\nKey methods for invoking the chat client with tools:")

ichatclient_methods = {}
for member in root.findall(".//member[@name]"):
    name = member.get('name')
    if name and name.startswith('M:Microsoft.Extensions.AI.IChatClient.'):
        method_name = name.split('.')[-1]
        if method_name in ['CompleteAsync', 'CompleteStreamingAsync']:
            summary = member.find('summary')
            summary_text = (summary.text or "").strip()[:80] if summary else ""
            if method_name not in ichatclient_methods:
                ichatclient_methods[method_name] = summary_text

for method, desc in sorted(ichatclient_methods.items()):
    print(f"\n  ✓ {method}(...)")
    if desc:
        print(f"    {desc}")

print("\n3. AITOOL STRUCTURE")
print("-" * 80)

for member in root.findall(".//member[@name]"):
    name = member.get('name')
    if name == 'T:Microsoft.Extensions.AI.AITool':
        summary = member.find('summary')
        if summary is not None and summary.text:
            print(f"\n{summary.text.strip()}")

        # Get properties/members
        print("\nProperties/Members:")
        break

for member in root.findall(".//member[@name]"):
    name = member.get('name')
    if name and name.startswith('P:Microsoft.Extensions.AI.AITool.'):
        prop_name = name.split('.')[-1]
        summary = member.find('summary')
        summary_text = (summary.text or "").strip()[:60] if summary else ""
        print(f"  - {prop_name}")
        if summary_text:
            print(f"    {summary_text}")

print("\n4. AIFUNCTIONFACTORY")
print("-" * 80)

for member in root.findall(".//member[@name]"):
    name = member.get('name')
    if name == 'T:Microsoft.Extensions.AI.AIFunctionFactory':
        summary = member.find('summary')
        print("\n✓ AIFunctionFactory")
        if summary is not None and summary.text:
            print(f"  {summary.text.strip()[:120]}")
        break

print("\n5. FUNCTION INVOCATION RELATED TYPES")
print("-" * 80)

func_types = [
    'T:Microsoft.Extensions.AI.FunctionInvokingChatClient',
    'T:Microsoft.Extensions.AI.AIFunction',
]

for func_type in func_types:
    for member in root.findall(".//member[@name]"):
        if member.get('name') == func_type:
            summary = member.find('summary')
            short_name = func_type.split('.')[-1]
            print(f"\n✓ {short_name}")
            if summary is not None and summary.text:
                text = summary.text.strip()[:100]
                print(f"  {text}")
            break

